import{_ as t,o as h,c,a0 as g}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"Nhà cung cấp","description":"","frontmatter":{"title":"Nhà cung cấp"},"headers":[],"relativePath":"supplier.md","filePath":"supplier.md"}'),a={name:"supplier.md"};function o(i,n,r,u,l,d){return h(),c("div",null,[...n[0]||(n[0]=[g('<h1 id="nha-cung-cap" tabindex="-1">Nhà cung cấp <a class="header-anchor" href="#nha-cung-cap" aria-label="Permalink to &quot;Nhà cung cấp&quot;">​</a></h1><h2 id="nha-cung-cap-la-gi" tabindex="-1">Nhà cung cấp là gì? <a class="header-anchor" href="#nha-cung-cap-la-gi" aria-label="Permalink to &quot;Nhà cung cấp là gì?&quot;">​</a></h2><p><strong>Nhà cung cấp</strong> (Supplier) là cá nhân hoặc tổ chức cung cấp sản phẩm hoặc dịch vụ cho doanh nghiệp của bạn. ABNERP giúp bạn quản lý toàn bộ vòng đời quan hệ với nhà cung cấp — từ đánh giá lựa chọn đến theo dõi hợp đồng và thanh toán.</p><h2 id="tao-nha-cung-cap-moi" tabindex="-1">Tạo nhà cung cấp mới <a class="header-anchor" href="#tao-nha-cung-cap-moi" aria-label="Permalink to &quot;Tạo nhà cung cấp mới&quot;">​</a></h2><h3 id="cac-buoc-thuc-hien" tabindex="-1">Các bước thực hiện <a class="header-anchor" href="#cac-buoc-thuc-hien" aria-label="Permalink to &quot;Các bước thực hiện&quot;">​</a></h3><ol><li>Truy cập <strong>Trang chủ &gt; Mua hàng &gt; Nhà cung cấp</strong> (hoặc tìm kiếm &quot;Nhà cung cấp&quot; trên thanh tìm kiếm)</li><li>Nhấn <strong>+ Thêm Nhà cung cấp</strong></li><li>Điền thông tin chi tiết</li><li>Nhấn <strong>Lưu</strong></li></ol><h3 id="cac-truong-thong-tin" tabindex="-1">Các trường thông tin <a class="header-anchor" href="#cac-truong-thong-tin" aria-label="Permalink to &quot;Các trường thông tin&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trường</th><th>Bắt buộc</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tên nhà cung cấp</strong></td><td>Có</td><td>Tên đầy đủ của nhà cung cấp (cá nhân hoặc tổ chức)</td></tr><tr><td><strong>Mã nhà cung cấp</strong></td><td>Có</td><td>Mã định danh duy nhất (tự động sinh hoặc nhập thủ công)</td></tr><tr><td><strong>Nhóm nhà cung cấp</strong></td><td>Có</td><td>Phân loại nhà cung cấp (ví dụ: Trong nước, Quốc tế, Ưu tiên)</td></tr><tr><td><strong>Loại nhà cung cấp</strong></td><td>Có</td><td>Cá nhân hoặc Tổ chức</td></tr><tr><td><strong>Địa chỉ</strong></td><td>Không</td><td>Địa chỉ của nhà cung cấp</td></tr><tr><td><strong>Email</strong></td><td>Không</td><td>Địa chỉ email liên hệ</td></tr><tr><td><strong>Điện thoại</strong></td><td>Không</td><td>Số điện thoại liên hệ</td></tr><tr><td><strong>Website</strong></td><td>Không</td><td>Trang web của nhà cung cấp</td></tr><tr><td><strong>Ngân hàng</strong></td><td>Không</td><td>Thông tin tài khoản ngân hàng để thanh toán</td></tr><tr><td><strong>Điều khoản thanh toán</strong></td><td>Không</td><td>Thời hạn thanh toán mặc định</td></tr></tbody></table><h2 id="nhom-nha-cung-cap" tabindex="-1">Nhóm nhà cung cấp <a class="header-anchor" href="#nhom-nha-cung-cap" aria-label="Permalink to &quot;Nhóm nhà cung cấp&quot;">​</a></h2><p><strong>Nhóm nhà cung cấp</strong> (Supplier Group) giúp bạn phân loại nhà cung cấp phục vụ báo cáo và tìm kiếm:</p><ul><li><strong>Trong nước</strong>: Nhà cung cấp trong nước</li><li><strong>Quốc tế</strong>: Nhà cung cấp nước ngoài</li><li><strong>Nhà sản xuất</strong>: Đối tác sản xuất trực tiếp</li><li><strong>Nhà phân phối</strong>: Đối tác phân phối</li><li><strong>Nhà thầu phụ</strong>: Đối tác gia công, thầu phụ</li></ul><p>Bạn có thể quản lý nhóm nhà cung cấp tại <strong>Trang chủ &gt; Mua hàng &gt; Nhóm nhà cung cấp</strong>.</p><h2 id="quy-trinh-nghiep-vu-lien-quan" tabindex="-1">Quy trình nghiệp vụ liên quan <a class="header-anchor" href="#quy-trinh-nghiep-vu-lien-quan" aria-label="Permalink to &quot;Quy trình nghiệp vụ liên quan&quot;">​</a></h2><p>Nhà cung cấp tham gia vào các quy trình nghiệp vụ sau:</p><ol><li><strong>Mua hàng — Yêu cầu mua hàng</strong>: Đề xuất mua hàng từ các bộ phận</li><li><strong>Mua hàng — Đơn mua hàng (PO)</strong>: Đặt hàng chính thức từ nhà cung cấp</li><li><strong>Kho — Nhập kho</strong>: Nhận hàng từ nhà cung cấp</li><li><strong>Kế toán — Hóa đơn mua hàng</strong>: Ghi nhận công nợ với nhà cung cấp</li><li><strong>Kế toán — Thanh toán</strong>: Chi tiền thanh toán cho nhà cung cấp</li></ol><h2 id="đanh-gia-nha-cung-cap" tabindex="-1">Đánh giá nhà cung cấp <a class="header-anchor" href="#đanh-gia-nha-cung-cap" aria-label="Permalink to &quot;Đánh giá nhà cung cấp&quot;">​</a></h2><p>ABNERP cho phép bạn đánh giá và xếp hạng nhà cung cấp dựa trên các tiêu chí:</p><ul><li><strong>Chất lượng sản phẩm</strong>: Tỷ lệ hàng lỗi, hàng trả lại</li><li><strong>Giao hàng</strong>: Đúng hạn, đúng số lượng</li><li><strong>Giá cả</strong>: Cạnh tranh, ổn định</li><li><strong>Dịch vụ</strong>: Hỗ trợ kỹ thuật, hậu mãi</li><li><strong>Thời gian thanh toán</strong>: Điều khoản thanh toán linh hoạt</li></ul><h2 id="meo-va-luu-y" tabindex="-1">Mẹo và lưu ý <a class="header-anchor" href="#meo-va-luu-y" aria-label="Permalink to &quot;Mẹo và lưu ý&quot;">​</a></h2><ul><li>Thiết lập đầy đủ thông tin ngân hàng để tự động điền vào chứng từ thanh toán</li><li>Sử dụng <strong>Nhóm nhà cung cấp</strong> để dễ dàng lọc và báo cáo chi phí theo nhóm</li><li>Theo dõi công nợ nhà cung cấp thường xuyên để tránh chậm thanh toán</li><li>Kích hoạt <strong>Cảnh báo tồn kho tối thiểu</strong> để tự động tạo yêu cầu mua hàng khi hàng sắp hết</li><li>Lưu trữ hợp đồng và thỏa thuận giá trong hồ sơ nhà cung cấp để dễ dàng tra cứu</li></ul>',20)])])}const e=t(a,[["render",o]]);export{s as __pageData,e as default};
